class Solution {
    public int numberOfSubstrings(String s) {
        int n = s.length();
        int res = 0;
        for (int i = 0; i < n; i++) {
            int[] count = new int[3];
            for (int j = i; j < n; j++) {
                count[s.charAt(j) - 'a']++;
                if (count[0] > 0 && count[1] > 0 && count[2] > 0) {
                    res++;
                }
            }
        }
        return res;
    }
}
